+fn random_genotype(rng: &mut StdRng, snp: &SnpDef) -> String {
+    let p = snp.maf;
+    let q = 1.0 - p;
+    let r: f64 = rng.gen();
+    if r < q * q { snp.hom_ref } else if r < q * q + 2.0 * p * q { snp.het } else { snp.hom_alt }.to_string()
+}
