+function parseFixtureToGenotypes(name) {
+  const text = loadFixture(name);
+  const data = rvdna.parse23andMe(text);
+  const gts = new Map();
+  for (const [rsid, snp] of data.snps) gts.set(rsid, snp.genotype);
+  return { data, gts };
+}
